import{_ as t,o as i,c as a,ag as e}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"2. テナントオンボーディング","description":"","frontmatter":{},"headers":[],"relativePath":"internal/02-onboarding.md","filePath":"internal/02-onboarding.md"}'),r={name:"internal/02-onboarding.md"};function o(n,l,d,p,s,h){return i(),a("div",null,[...l[0]||(l[0]=[e(`<h1 id="_2-テナントオンボーディング" tabindex="-1">2. テナントオンボーディング <a class="header-anchor" href="#_2-テナントオンボーディング" aria-label="Permalink to &quot;2. テナントオンボーディング&quot;">​</a></h1><p>新規テナント（契約企業）の立ち上げ手順です。</p><h2 id="_2-1-オンボーディング全体フロー" tabindex="-1">2.1 オンボーディング全体フロー <a class="header-anchor" href="#_2-1-オンボーディング全体フロー" aria-label="Permalink to &quot;2.1 オンボーディング全体フロー&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. テナント作成 → 2. オーナーアカウント作成 → 3. 店舗作成 →</span></span>
<span class="line"><span>4. 初期設定 → 5. メニュー登録 → 6. テーブル登録 →</span></span>
<span class="line"><span>7. プラン機能の有効化 → 8. 決済設定（proプラン以上） → 9. 運用開始</span></span></code></pre></div><hr><h2 id="_2-2-ステップ1-テナント作成" tabindex="-1">2.2 ステップ1：テナント作成 <a class="header-anchor" href="#_2-2-ステップ1-テナント作成" aria-label="Permalink to &quot;2.2 ステップ1：テナント作成&quot;">​</a></h2><p>POSLA管理画面の「テナント作成」タブで新規テナントを登録します。</p><ol><li>スラッグを決定します（例：<code>shibuya-ramen</code>） <ul><li>英小文字・数字・ハイフンのみ</li><li>一度決めると変更不可</li></ul></li><li>テナント名を入力します（例：「渋谷ラーメン」）</li><li>プランを選択します（standard / pro / enterprise）</li><li>「作成」をクリックします</li></ol><hr><h2 id="_2-3-ステップ2-オーナーアカウント作成" tabindex="-1">2.3 ステップ2：オーナーアカウント作成 <a class="header-anchor" href="#_2-3-ステップ2-オーナーアカウント作成" aria-label="Permalink to &quot;2.3 ステップ2：オーナーアカウント作成&quot;">​</a></h2><p>テナント作成後、テナントのオーナーアカウントを作成する必要があります。</p><p><strong>方法：</strong> テナントのログインURLにアクセスし、セットアップを行います。またはAPIを直接呼び出してオーナーユーザーを作成します。</p><p><strong>オーナーに伝える情報：</strong></p><ul><li>ログインURL：<code>https://ドメイン/admin/</code></li><li>ユーザー名</li><li>初期パスワード</li></ul><hr><h2 id="_2-4-ステップ3-店舗作成" tabindex="-1">2.4 ステップ3：店舗作成 <a class="header-anchor" href="#_2-4-ステップ3-店舗作成" aria-label="Permalink to &quot;2.4 ステップ3：店舗作成&quot;">​</a></h2><p>オーナーがオーナーダッシュボードの「店舗管理」タブから店舗を作成します。</p><p><strong>必要な情報：</strong></p><ul><li>店舗名</li><li>店舗名（英語、任意）</li><li>スラッグ（英小文字・数字・ハイフン）</li></ul><hr><h2 id="_2-5-ステップ4-初期設定" tabindex="-1">2.5 ステップ4：初期設定 <a class="header-anchor" href="#_2-5-ステップ4-初期設定" aria-label="Permalink to &quot;2.5 ステップ4：初期設定&quot;">​</a></h2><p>店舗作成後、マネージャーまたはオーナーが管理ダッシュボードの「店舗設定」から以下を設定します。</p><table tabindex="0"><thead><tr><th>設定項目</th><th>説明</th><th>優先度</th></tr></thead><tbody><tr><td>営業日区切り時刻</td><td>深夜営業の場合は調整必要</td><td>高</td></tr><tr><td>税率</td><td>10%のままでOKの場合は変更不要</td><td>中</td></tr><tr><td>注文上限</td><td>必要に応じて調整</td><td>低</td></tr><tr><td>ラストオーダー時刻</td><td>自動ラストオーダーが必要な場合</td><td>中</td></tr><tr><td>レジ設定</td><td>支払方法の有効/無効</td><td>高</td></tr><tr><td>レシート設定</td><td>店舗名・住所・電話番号</td><td>高</td></tr><tr><td>外観カスタマイズ</td><td>ブランドカラー・ロゴ</td><td>中</td></tr></tbody></table><hr><h2 id="_2-6-ステップ5-メニュー登録" tabindex="-1">2.6 ステップ5：メニュー登録 <a class="header-anchor" href="#_2-6-ステップ5-メニュー登録" aria-label="Permalink to &quot;2.6 ステップ5：メニュー登録&quot;">​</a></h2><p>管理ダッシュボードの「メニュー管理」タブから登録します。</p><p><strong>登録順序：</strong></p><ol><li>カテゴリの作成（前菜、メイン、ドリンク等）</li><li>メニューテンプレートの作成（品名、価格、画像等）</li><li>オプショングループの作成（トッピング、サイズ等）</li><li>オプションとメニューの紐付け</li></ol><div class="tip custom-block"><p class="custom-block-title">CSVインポート</p><p>大量のメニューがある場合、CSVインポート機能を利用すると効率的です。</p></div><hr><h2 id="_2-7-ステップ6-テーブル登録" tabindex="-1">2.7 ステップ6：テーブル登録 <a class="header-anchor" href="#_2-7-ステップ6-テーブル登録" aria-label="Permalink to &quot;2.7 ステップ6：テーブル登録&quot;">​</a></h2><p>管理ダッシュボードの「テーブル・フロア」タブから登録します。</p><ol><li>テーブルコードと座席数を設定</li><li>QRコードを生成・印刷</li><li>テーブルにQRコードを設置</li></ol><hr><h2 id="_2-8-ステップ7-プラン機能の有効化" tabindex="-1">2.8 ステップ7：プラン機能の有効化 <a class="header-anchor" href="#_2-8-ステップ7-プラン機能の有効化" aria-label="Permalink to &quot;2.8 ステップ7：プラン機能の有効化&quot;">​</a></h2><p>テナントのプランに応じて、機能が自動的に有効/無効になります。POSLA管理画面で設定したプランに基づき、<code>plan_features</code>テーブルの定義に従って機能が制御されます。</p><p>プランのアップグレードはStripe Billingのサブスクリプション変更で行います。</p><hr><h2 id="_2-9-ステップ8-決済設定-proプラン以上" tabindex="-1">2.9 ステップ8：決済設定（proプラン以上） <a class="header-anchor" href="#_2-9-ステップ8-決済設定-proプラン以上" aria-label="Permalink to &quot;2.9 ステップ8：決済設定（proプラン以上）&quot;">​</a></h2><p>Stripe決済を有効にする場合、以下のいずれかの方式を選択します。</p><p><strong>パターンA：テナントが自前のStripeアカウントを持っている場合</strong></p><ol><li>オーナーダッシュボードの「決済設定」タブを開く</li><li>「Stripe Secret Key」欄にテナントのSecret Keyを入力して保存</li><li>レジの Stripe Terminal が直ちに利用可能（<code>terminal_pattern=A</code>）</li></ol><p><strong>パターンB：テナントが自前のStripeアカウントを持っていない場合</strong></p><ol><li>オーナーダッシュボードの「決済設定」タブを開く</li><li>「Stripe Connectに登録して決済を開始する」をクリック</li><li>Stripeのオンボーディング画面で必要情報を入力</li><li><code>connect_onboarding_complete=1</code> になり、レジの Stripe Terminal が利用可能（<code>terminal_pattern=B</code>、application_fee 1.0% をPOSLAが取得）</li></ol><hr><h2 id="_2-10-ステップ9-運用開始" tabindex="-1">2.10 ステップ9：運用開始 <a class="header-anchor" href="#_2-10-ステップ9-運用開始" aria-label="Permalink to &quot;2.10 ステップ9：運用開始&quot;">​</a></h2><p>全設定完了後のチェックリスト：</p><ul><li>[ ] テナントが有効化されている</li><li>[ ] オーナーがログインできる</li><li>[ ] 店舗が作成されている</li><li>[ ] メニューが登録されている</li><li>[ ] テーブルが登録され、QRコードが印刷されている</li><li>[ ] レシート設定が完了している</li><li>[ ] 支払方法が設定されている</li><li>[ ] スタッフアカウントが作成されている</li><li>[ ] KDS端末が設置され、動作確認済み</li><li>[ ] セルフオーダーのQRコードをスマートフォンで読み取って注文テスト済み</li></ul><hr><h2 id="_2-11-スタッフへの導入ガイダンス" tabindex="-1">2.11 スタッフへの導入ガイダンス <a class="header-anchor" href="#_2-11-スタッフへの導入ガイダンス" aria-label="Permalink to &quot;2.11 スタッフへの導入ガイダンス&quot;">​</a></h2><p>テナントのスタッフに以下を説明してください。</p><p><strong>全スタッフ：</strong></p><ul><li>ログイン方法（ユーザー名＋パスワード）</li><li>退勤時のログアウトの重要性</li><li>出退勤打刻の方法</li></ul><p><strong>ホールスタッフ：</strong></p><ul><li>ハンディPOSの操作方法（注文入力、テーブル選択）</li><li>スタッフ呼び出しアラートの確認・対応方法</li></ul><p><strong>キッチンスタッフ：</strong></p><ul><li>KDSの操作方法（調理開始→完成→提供済み）</li><li>ステーション選択の方法</li><li>コースフェーズの進め方（コースがある場合）</li></ul><p><strong>レジスタッフ：</strong></p><ul><li>POSレジの操作方法（テーブル選択→支払方法→確定）</li><li>レジ開け・閉めの方法</li><li>個別会計の操作方法</li></ul><p><strong>マネージャー：</strong></p><ul><li>管理ダッシュボードの全タブの概要</li><li>シフト管理の操作（proプランの場合）</li><li>レポートの見方</li></ul>`,61)])])}const _=t(r,[["render",o]]);export{u as __pageData,_ as default};
